package com.example.demo.services;
import com.example.demo.dto.LoteProductoDTO;import com.example.demo.models.LoteProducto;import com.example.demo.repository.LoteProductoRepository;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.LocalDate;import java.util.List;
@Service public class LoteService{private final LoteProductoRepository repository;private final ReglasOperativasService reglas;public LoteService(LoteProductoRepository repository,ReglasOperativasService reglas){this.repository=repository;this.reglas=reglas;}
    @Transactional(readOnly=true)public List<LoteProductoDTO> proximosAVencer(int dias){LocalDate hoy=LocalDate.now();int alerta=reglas.obtener().diasAlertaVencimiento();return repository.findByActivoTrueAndCantidadDisponibleGreaterThanAndFechaVencimientoBetweenOrderByFechaVencimientoAsc(0,hoy,hoy.plusDays(dias)).stream().map(l->dto(l,alerta)).toList();}
    @Transactional(readOnly=true)public List<LoteProductoDTO> porProducto(Long id){int alerta=reglas.obtener().diasAlertaVencimiento();return repository.findByProductoIdOrderByFechaVencimientoAsc(id).stream().map(l->dto(l,alerta)).toList();}
    private LoteProductoDTO dto(LoteProducto l,int dias){LocalDate hoy=LocalDate.now();String estado=l.getCantidadDisponible()==0?"AGOTADO":l.getFechaVencimiento()!=null&&l.getFechaVencimiento().isBefore(hoy)?"VENCIDO":l.getFechaVencimiento()!=null&&!l.getFechaVencimiento().isAfter(hoy.plusDays(dias))?"PRÓXIMO":"VIGENTE";return new LoteProductoDTO(l.getId(),l.getProducto().getId(),l.getProducto().getNombre(),l.getCodigoLote(),l.getFechaIngreso(),l.getFechaVencimiento(),l.getCantidadInicial(),l.getCantidadDisponible(),l.getCostoUnitario(),estado);}}
